use std::pin::Pin;
let val = 42;
let pinned = Pin::new(&val);

use std::pin::Pin;
let val = String::from("hello");
let pinned = Pin::new(&val);
let pin_ref = pinned.as_ref();

use std::pin::Pin;
let mut val = String::from("hello");
let mut pinned = Pin::new(&mut val);
let pin_mut = pinned.as_mut();

use std::pin::Pin;
let val = 42;
let pinned = Pin::new(&val);
assert_eq!(*pinned.get_ref(), 42);

use std::pin::Pin;
let val = 42;
let pinned = Pin::new(&val);
let reference = Pin::into_inner(pinned);
